proof fn phi_1_leads_to_unfold_intensional_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>, i: nat)
    requires
        p.leads_to(q).satisfied_by(ex),
    ensures
        p.implies(eventually(q)).satisfied_by(ex.suffix(i)),
{
    leads_to_unfold::<int>(ex, p, q);
}

proof fn phi_2_implies_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.satisfied_by(ex),
        (p.pred)(ex) ==> (q.pred)(ex),
    ensures
        q.satisfied_by(ex),
{
    implies_apply::<int>(ex, p, q);
}

proof fn phi_3_execution_equality_forces_fn_equality(f: spec_fn(nat) -> int, g: spec_fn(nat) -> int)
    requires
        forall |i: nat| #[trigger] f(i) == g(i),
    ensures
        f == g,
{
    let ex1 = Execution { nat_to_state: f };
    let ex2 = Execution { nat_to_state: g };
    execution_equality::<int>(ex1, ex2);
}

proof fn phi_4_suffix_zero_equals_self(ex: Execution<int>)
    ensures
        ex.suffix(0) == ex,
{
    assert forall |i: nat| #[trigger] (ex.suffix(0).nat_to_state)(i) == (ex.nat_to_state)(i) by {
        assert((ex.suffix(0).nat_to_state)(i) == (ex.nat_to_state)(i + 0));
    };
    execution_equality::<int>(ex.suffix(0), ex);
}

proof fn phi_5_leads_to_apply_any_spec(p: TempPred<int>, q: TempPred<int>, spec: TempPred<int>)
    requires
        spec.entails(p),
        spec.entails(p.leads_to(q)),
    ensures
        spec.entails(eventually(q)),
{
    leads_to_apply::<int>(spec, p, q);
}
